Review status: 0 of 3 files reviewed at latest revision, 2 unresolved discussions.

---

*[ui/js/controllers/perf/compare.js, line 132 \[r1\]](https://reviewable.io:443/reviews/mozilla/treeherder/1682#-KMZrpx9HBrTCCfGuKHm:-KMZrpxAbWXITtQJcqkW:877378526) ([raw file](https://github.com/mozilla/treeherder/blob/4d616ea97679979f074e77f0c11433cd1a102a2e/ui/js/controllers/perf/compare.js#L132)):*
> ```JavaScript
>                     console.log("Orignal Revision has not been given");
>                 }
>                 ThResultSetModel.getResultSetsFromRevision($scope.newProject.name, $scope.newRevision).then(
> ```

So I realized looking at this code that this code is error prone (since it would produce incorrect behaviour if the newrevision request finished before originalRevision). Instead, we should be chaining these two promises together if both are defined (or just look at the new revision promise if only new revision is set), something like:

```js
var originalRevisionPromise;
if ($scope.originalRevision.length) {
   originalRevisionPromise = ThResultSetModel.getResultSetsFromRevision($scope.originalProject.name, $scope.originalRevision).then(...);
}
var newRevisionPromise = ThResultSetModel.getResultSetsFromRevision($scope.newProject.name, $scope.newRevision).then(...);

$q.all([originalRevisionPromise, newRevisionPromise]).then(function() {
   if ($scope.originalRevisionError === undefined && $scope.newRevisionError === undefined && $scope.originalRevision.length) {
      $state.go(...);
   }
}
});
```

